<?php
namespace App\Http\Controllers\Tenant;use App\Http\Controllers\Controller;use App\Models\{Task,WorkProof};use App\Support\CurrentWorkspace;use Illuminate\Http\Request;use Illuminate\Validation\Rule;
class WorkProofController extends Controller{use Concerns;public function store(Request $r,Task $task,CurrentWorkspace $cw){$this->requirePerm('tenant.proofs.upload');$w=$this->ws($cw);$d=$r->validate(['proof_type'=>['required',Rule::in(WorkProof::TYPES)],'title'=>'nullable|string|max:255','note'=>'nullable|string','url'=>'nullable|url','daily_report_id'=>'nullable|exists:daily_reports,id','file'=>'nullable|file|max:10240']);if($r->hasFile('file')){$f=$r->file('file');$d+=['file_path'=>$f->store("workspaces/{$w->id}/tasks/{$task->id}/proofs"),'original_name'=>$f->getClientOriginalName(),'mime_type'=>$f->getMimeType(),'file_size'=>$f->getSize()];}$proof=WorkProof::create($d+['workspace_id'=>$w->id,'task_id'=>$task->id,'submitted_by'=>$r->user()->id,'status'=>'submitted']);return back()->with('status','Proof submitted.');}public function index(){ $this->requirePerm('tenant.proofs.review');return view('tenant.proof-review.index',['proofs'=>WorkProof::with('task','submitter')->where('status','submitted')->latest()->paginate(15)]);}public function approve(Request $r,WorkProof $proof){$this->requirePerm('tenant.proofs.approve');$proof->update(['status'=>'approved','reviewed_by'=>$r->user()->id,'reviewed_at'=>now()]);return back();}public function reject(Request $r,WorkProof $proof){$this->requirePerm('tenant.proofs.reject');$d=$r->validate(['rejection_reason'=>'required|string']);$proof->update($d+['status'=>'rejected','reviewed_by'=>$r->user()->id,'reviewed_at'=>now()]);return back();}}
